# HashMap Example Code

```
import java.util.HashMap;
import java.util.Map;
class HashMapTest {
 public static void main(String [] args) {
  int hashcode;
  String key;
  double value;
  int index, capacity = 16;
  HashMap<String, Double> map = new HashMap<>(); // initialize a HashMap
  // add entries, next we can retrieve them
  for (Map.Entry<String, Double> e : map.entrySet()) { // enumerate
   key = e.getKey();
   value = e.getValue();
   hashcode = e.hashCode();
   index = hashcode & (capacity-1);
   System.out.println("Key: "+key+" Value: "+value
    +" HashCode: "+hashcode+" Index: "+index);
  }
 }
}
